function showStockColumn(){if(route!=='inventory')return;let table=$('#view table');if(!table||table.dataset.stockColumn)return;table.dataset.stockColumn='true';let header=table.querySelector('thead tr');header.children[4].insertAdjacentHTML('beforebegin','<th>Stock total</th>');table.querySelectorAll('tbody tr').forEach(row=>{let code=row.cells[0]?.textContent.trim(),asset=findAssetByCode(code);if(asset)row.cells[4].insertAdjacentHTML('beforebegin',`<td><strong>${totalStock(asset)}</strong> ${asset.type==='Consumible'?'unid.':'unidad'}</td>`)});}
