function family(id){return state.families.find(f=>f.id===id)} function tag(status){let c=status==='Operativo'||status==='Aprobado'?'ok':status==='Stock bajo'||status==='En inspección'||status==='Pendiente'||status==='Pendiente de plazo'||status==='En corrección'?'warning':status==='Fuera de servicio'||status==='No aprobado'||status==='Bloqueado'?'bad':'neutral';return `<span class="tag ${c}">${status}</span>`}
function normalizeCode(value){let raw=String(value||'').toUpperCase().trim().replace(/[^A-Z0-9]/g,'');let m=raw.match(/^([A-Z]+)0*([0-9]+)$/);return m?`${m[1]}-${Number(m[2])}`:raw}
function codeMatches(a,b){return normalizeCode(a)===normalizeCode(b)}
function findAssetByCode(value){return state.assets.find(a=>codeMatches(a.code,value)||a.id===value)}
function ensureInventoryModel(){state.costCenters=state.costCenters||[];state.assignments=state.assignments||[];state.workerSignatures=state.workerSignatures||{};if(!state.costCenters.some(c=>c.name==='En tránsito'))state.costCenters.push({id:'transito',name:'En tránsito',inspectors:[],approvers:[],workers:[]});state.costCenters.forEach(c=>{c.inspectors=c.inspectors||[];c.approvers=c.approvers||[];c.workers=c.workers||[];c.safetyAdvisorName=c.safetyAdvisorName||'';c.safetyAdvisorSignature=c.safetyAdvisorSignature||''});state.assets.forEach(a=>{if(!a.stocks){a.stocks={};a.stocks[a.location||'Bodega Central']=Number(a.stock||1)}Object.keys(a.stocks).forEach(k=>a.stocks[k]=Number(a.stocks[k]||0));a.stock=Object.entries(a.stocks).filter(([k])=>k!=='En tránsito').reduce((sum,[,v])=>sum+Number(v||0),0);if(a.type==='Activo'&&!a.location){let found=Object.entries(a.stocks).find(([,v])=>Number(v)>0);a.location=found?.[0]||'Bodega Central'}})}
function centerNames(){ensureInventoryModel();return state.costCenters.map(c=>c.name)}
function centerOptions(selected){return centerNames().map(n=>`<option value="${n}" ${n===selected?'selected':''}>${n}</option>`).join('')}
function stockAt(a,center){ensureInventoryModel();return Number(a.stocks?.[center]||0)}
function totalStock(a){ensureInventoryModel();return Object.values(a.stocks||{}).reduce((sum,v)=>sum+Number(v||0),0)}
function setStockAt(a,center,value){ensureInventoryModel();a.stocks[center]=Math.max(0,Number(value||0));a.stock=Object.entries(a.stocks).filter(([k])=>k!=='En tránsito').reduce((sum,[,v])=>sum+Number(v||0),0)}
function moveStock(a,from,to,qty,status){ensureInventoryModel();qty=Math.max(1,Number(qty||1));from=from||a.location||activeUser().costCenter||'Bodega Central';to=to||activeUser().costCenter||'Bodega Central';let landing=status==='En tránsito'?'En tránsito':to;if(a.type==='Consumible'){if(from!==landing)setStockAt(a,from,stockAt(a,from)-qty);setStockAt(a,landing,stockAt(a,landing)+qty);a.status=a.stock<=Number(a.minimum||0)?'Stock bajo':'Disponible'}else{Object.keys(a.stocks).forEach(k=>a.stocks[k]=0);setStockAt(a,landing,1);a.location=landing;a.responsible=landing==='En tránsito'?`En tránsito a ${to}`:to;a.status=landing==='En tránsito'?'En tránsito':'Operativo';a.transferTo=landing==='En tránsito'?to:''}return {from,to,landing,qty}}
function stockSummaryRows(){ensureInventoryModel();return state.assets.map(a=>`<tr><td><strong>${a.name}</strong><br><span class="code">${a.code}</span></td><td><strong>${totalStock(a)}</strong></td>${centerNames().map(c=>`<td>${stockAt(a,c)||''}</td>`).join('')}</tr>`).join('')}
function parseWorker(raw,center){let [name,email,phone]=String(raw||'').split(/[|;]/).map(x=>x.trim());return {name:name||raw,email:email||'',phone:phone||'',center:center.name}}
function allWorkers(){ensureInventoryModel();return state.costCenters.filter(c=>c.name!=='En tránsito').flatMap(c=>(c.workers||[]).map(w=>parseWorker(w,c)))}
function workerOptions(selected){let workers=allWorkers();return workers.length?workers.map(w=>`<option value="${w.name}|${w.email}|${w.phone}|${w.center}" ${w.name===selected?'selected':''}>${w.name} · ${w.center}${w.phone?` · ${w.phone}`:w.email?` · ${w.email}`:''}</option>`).join(''):'<option value="">Sin trabajadores configurados</option>'}
function activeCustody(a){ensureInventoryModel();return state.assignments.find(x=>x.assetId===a.id&&x.kind==='Activo'&&x.status!=='Devuelto')}
function eppLabel(a){return isEpp(a)?'Sí, requiere aceptación digital':'No'}
function assignmentUrl(x){return `${location.origin}${location.pathname}?accept=${encodeURIComponent(x.token)}`}
function cleanPhone(value){return String(value||'').replace(/\D/g,'')}
